import numpy as np

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = grid.copy()
    bg = int(grid[0, 0])

    # Find key row
    key_row_idx = None
    key_colors = []
    for r in range(H-1, -1, -1):
        non_bg = [(c, int(grid[r, c])) for c in range(W) if grid[r, c] != bg]
        if non_bg:
            key_row_idx = r
            key_colors = [color for _, color in non_bg]
            break

    # Count colors to find box_color
    from collections import Counter
    color_counts = Counter()
    for r in range(H):
        if r == key_row_idx:
            continue
        for c in range(W):
            v = int(grid[r, c])
            if v != bg:
                color_counts[v] += 1
    box_color = color_counts.most_common(1)[0][0]

    # Find center color regions
    centers = []
    visited = set()

    for r in range(H):
        if r == key_row_idx:
            continue
        for c in range(W):
            v = int(grid[r, c])
            if v != bg and v != box_color and (r, c) not in visited:
                color = v
                cells = []
                stack = [(r, c)]
                while stack:
                    cr, cc = stack.pop()
                    if (cr, cc) in visited or cr < 0 or cr >= H or cc < 0 or cc >= W:
                        continue
                    if cr == key_row_idx:
                        continue
                    if int(grid[cr, cc]) != color:
                        continue
                    visited.add((cr, cc))
                    cells.append((cr, cc))
                    for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                        stack.append((cr+dr, cc+dc))

                if cells:
                    min_r = min(cr for cr, cc in cells)
                    max_r = max(cr for cr, cc in cells)
                    min_c = min(cc for cr, cc in cells)
                    max_c = max(cc for cr, cc in cells)

                    # Find enclosing box
                    box_top = min_r
                    while box_top > 0 and grid[box_top-1, min_c] != bg:
                        box_top -= 1
                    box_bottom = max_r
                    while box_bottom < H-1 and grid[box_bottom+1, min_c] != bg:
                        box_bottom += 1
                    box_left = min_c
                    while box_left > 0 and grid[min_r, box_left-1] != bg:
                        box_left -= 1
                    box_right = max_c
                    while box_right < W-1 and grid[min_r, box_right+1] != bg:
                        box_right += 1

                    centers.append({
                        'color': color,
                        'min_r': min_r, 'max_r': max_r,
                        'min_c': min_c, 'max_c': max_c,
                        'box_top': box_top, 'box_bottom': box_bottom,
                        'box_left': box_left, 'box_right': box_right,
                    })

    # Assign grid positions
    box_rows = sorted(set(c['box_top'] for c in centers))
    box_cols = sorted(set(c['box_left'] for c in centers))

    grid_map = {}
    for center in centers:
        gr = box_rows.index(center['box_top'])
        gc = box_cols.index(center['box_left'])
        center['grid_row'] = gr
        center['grid_col'] = gc
        grid_map[(gr, gc)] = center

