                        for nc in next_cands:
                            if nc in get_adjacent(cand):
                                current_pos = cand
                                found = True
                                break
                        if found:
                            break
                if not found:
                    current_pos = candidates[0]
        else:
            found = False
            for cand in candidates:
                if cand in get_adjacent(current_pos):
                    current_pos = cand
                    found = True
                    break
            if not found and candidates:
                current_pos = candidates[0]

        used_positions.add(current_pos)
        path.append((current_pos, color))

    # Fill gaps
    for i in range(len(path) - 1):
        pos_a, color_a = path[i]
        pos_b, color_b = path[i+1]

        box_a = grid_map[pos_a]
        box_b = grid_map[pos_b]

        fill_color = color_a

        if pos_a[0] == pos_b[0]:  # Same row
            if pos_a[1] < pos_b[1]:
                gap_left = box_a['box_right'] + 1
                gap_right = box_b['box_left'] - 1
            else:
                gap_left = box_b['box_right'] + 1
                gap_right = box_a['box_left'] - 1

            for r in range(box_a['min_r'], box_a['max_r'] + 1):
                for c in range(gap_left, gap_right + 1):
                    output[r, c] = fill_color

        elif pos_a[1] == pos_b[1]:  # Same column
            if pos_a[0] < pos_b[0]:
                gap_top = box_a['box_bottom'] + 1
                gap_bottom = box_b['box_top'] - 1
            else:
                gap_top = box_b['box_bottom'] + 1
                gap_bottom = box_a['box_top'] - 1

            for c in range(box_a['min_c'], box_a['max_c'] + 1):
                for r in range(gap_top, gap_bottom + 1):
                    output[r, c] = fill_color

    return output.tolist()

